.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1rem;
  padding: 1rem;
}

.gallery img {
  width: 100%;
  height: 250px;
  object-fit: cover;
  border-radius: 8px;
  transition: transform 0.3s ease;
}

.gallery img:hover {
  transform: scale(1.05);
}

.star-rating {
  --percent: calc(var(--rating) / 5 * 100%);
  display: inline-block;
  font-size: 2rem;
  font-family: Times;
  line-height: 1;
}

.star-rating::before {
  content: '★★★★★';
  background: linear-gradient(90deg, #ffc107 var(--percent), #e0e0e0 var(--percent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}
/* Usage: <div class='star-rating' style='--rating: 3.5'></div> */

nav {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  align-items: center;
  padding: 1rem;
  background: #1a1a2e;
}

.nav-links {
  display: flex;
  gap: 1.5rem;
  list-style: none;
  flex-wrap: wrap;
}

.nav-links a {
  color: #e0e0e0;
  text-decoration: none;
  padding: 0.5rem;
  transition: color 0.2s;
}

.nav-links a:hover { color: #00d4ff; }

@media (max-width: 768px) {
  nav { flex-direction: column; gap: 1rem; }
  .nav-links { flex-direction: column; text-align: center; }
}

.progress-bar {
  width: 100%;
  height: 20px;
  background: #e0e0e0;
  border-radius: 10px;
  overflow: hidden;
}

.progress-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, #4caf50, #81c784);
  border-radius: 10px;
  width: var(--progress, 0%);
  transition: width 0.6s ease;
  animation: shimmer 2s infinite;
}

@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
/* Usage: <div class='progress-bar'><div class='progress-bar-fill' style='--progress:75%'></div></div> */

.switch input {
  display: none;
}

.switch label {
  display: inline-block;
  width: 50px;
  height: 26px;
  background: #ccc;
  border-radius: 13px;
  position: relative;
  cursor: pointer;
  transition: background 0.3s;
}

.switch label::after {
  content: '';
  position: absolute;
  top: 3px;
  left: 3px;
  width: 20px;
  height: 20px;
  background: white;
  border-radius: 50%;
  transition: transform 0.3s;
}

.switch input:checked + label { background: #4caf50; }
.switch input:checked + label::after { transform: translateX(24px); }
/* <div class='switch'><input type='checkbox' id='t'><label for='t'></label></div> */
